  required: ["scan_time", "market_mood", "stocks"]
};

// Robust JSON Parser
const robustParse = (text: string): any => {
  if (!text) return null;
  let clean = text.trim();
  clean = clean.replace(/^```[a-z]*\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');
  const firstBrace = clean.search(/[{[]/);
  const lastIndex = Math.max(clean.lastIndexOf('}'), clean.lastIndexOf(']'));
  if (firstBrace !== -1 && lastIndex !== -1) clean = clean.substring(firstBrace, lastIndex + 1);
  try {
    return JSON.parse(clean);
  } catch (e) {
    return null;
  }
};

export const fetchChiNextScanning = async (
  apiKey: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    作为资深 A 股量化交易员，请利用 googleSearch 实时扫描今日（${dateStr}）创业板 (ChiNext) 市场的活跃标的。

    [!!! 扫描指令 !!!]
    1. 目标范围：创业板成交额前 30 名、涨幅居前或有显著异动（放量、封板、反包）的个股。
    2. 核心量化指标：
       - 主力控盘分 (0-100)：基于今日主力资金净流入、筹码集中度、拉升斜率进行打分。
       - 主力核心成本：检索该股最近 5-10 个交易日的平均成交价作为主力基准成本。
       - 安全垫空间：当前价与主力核心成本的差值百分比。
       - 战法评级：[起爆]（放量突破）、[锁筹]（缩量横盘）、[分歧]（剧烈震荡）、[出货]（高位放量下杀）、[潜伏]（底部异动）。
    3. 实时性：必须确保获取的是今日真实的盘面数据。

    请输出严格格式的 JSON。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: chiNextScanSchema
    }
  });

  const parsed = robustParse(response.text || "{}");

  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    chiNextScanData: parsed,
    market: MarketType.CN
  };
};

export const fetchKLineSynergyAnalysis = async (
  query: string,
  base64Image: string | null,
  market: MarketType,
  apiKey: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    作为资深 A 股技术面与资金博弈专家，请针对标的 "${query}" 进行【3-5日K线合力分析】。

    [!!! 核心任务 !!!]
    1. 形态解构：识别最近 3-5 个交易日的 K 线组合形态（如：多方炮、揉搓线、仙人指路等）。
    2. 合力测算：通过联网检索该股最近 3 日的【主力净流入/流出】数据和【成交量变化】。判断是“机构与游资共振”还是“散户跟风”。
    3. 视觉校准：${base64Image ? "必须根据上传的 K 线截图，识别图中每一根 K 线实体的收盘价位置、上下影线长度。" : "根据联网检索的最新 OHLVC 数据进行分析。"}
    4. 趋势预判：基于当前合力状态，预判后续 1-3 日的走势（进攻、洗盘、补跌）。

    请输出严格格式的 JSON。
  `;

  const contents: any = { parts: [{ text: prompt }] };
  if (base64Image) {
    contents.parts.push({
      inlineData: { mimeType: 'image/jpeg', data: base64Image }
    });
  }

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: klineSynergySchema
    }
  });

  const parsed = robustParse(response.text || "{}");

  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    klineSynergyData: parsed,
    market
  };
};

