                performance: { type: Type.STRING },
                health_score: { type: Type.NUMBER },
                logic: { type: Type.STRING }
              },
              required: ["name", "code", "price", "status", "performance", "health_score", "logic"]
            }
          }
        },
        required: ["tier", "stocks"]
      }
    },
    structural_integrity: {
      type: Type.OBJECT,
      properties: {
        synergy_score: { type: Type.NUMBER },
        verdict: { type: Type.STRING },
        is_divergent: { type: Type.BOOLEAN }
      },
      required: ["synergy_score", "verdict", "is_divergent"]
    },
    support_points: { type: Type.ARRAY, items: { type: Type.STRING } },
    warning_signals: { type: Type.ARRAY, items: { type: Type.STRING } },
    action_advice: { type: Type.STRING }
  },
  required: ["sector_name", "cycle_stage", "stage_label", "risk_score", "ladder", "structural_integrity", "support_points", "warning_signals", "action_advice"]
};

export const fetchSectorLadderAnalysis = async (sectorName: string, market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric' });
  const nextYear = now.getFullYear() + 1;

  const prompt = `
    作为顶级 A 股量化专家，深度研判板块：“${sectorName}” 的生命周期及梯队结构。

    [!!! 核心强制指令 !!!]:
    1. 当前现实世界的真实日期是：${dateStr}。禁止认为这是未来 or 模拟。
    2. 实时股价对齐：必须利用 googleSearch 强制联网检索该标的【今日（${dateStr}）】的真实报价（包括盘中价或最新收盘价）。
    3. 年度切换逻辑：现在已进入 ${now.getFullYear()} 年末，任何关于“明年”或“开门红”的预判必须以 **${nextYear} 年** 为准。
    4. 如果搜索结果显示 2024 年，请将其理解为最近的历史存量数据，但你的分析基准点必须定在 ${now.getFullYear()} 年末及 ${nextYear} 年初。

    【严苛判别准则】
    - 凋零特征识别：如果跌破 60 日线或年线，且成交量萎缩，归类为 "Receding" (退潮期)。
    - 梯队识别：清晰拆解一梯队（领涨）、二梯队（中军）、三梯队（补涨）。

    请输出严格的 JSON。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: sectorLadderSchema
    }
  });

  const text = response.text || "{}";
  const parsed = robustParse(text);

  return {
    content: text,
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    ladderData: parsed,
    market
  };
};

import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ModelProvider, MarketType, AnalysisResult, ChiNextScanItem } from '../types';
import { fetchChiNextScanning } from '../services/geminiService';
import { ScanEye, Loader2, Search, ArrowRight, Activity, Zap, Target, Info, Flame, TrendingUp, Compass, ShieldAlert, BarChart3, Rocket, Lock, Share2, Skull, RefreshCw, CheckCircle, ZapOff } from 'lucide-react';

export const KLineMaster: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);
  const [sortKey, setSortKey] = useState<keyof ChiNextScanItem>('control_score');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(p => p + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleScan = async () => {
    if (!settings.geminiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchChiNextScanning(settings.geminiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "合力扫描失败，请检查网络或 API 配置");
    } finally {
      setLoading(false);
    }
  };

  const handleNavigateToStock = (code: string, name: string) => {
    navigate(`/stock?q=${encodeURIComponent(code + " " + name)}`);
  };

  const scanData = result?.chiNextScanData;

  const sortedStocks = scanData?.stocks?.sort((a, b) => {
    const valA = a[sortKey];
    const valB = b[sortKey];
    if (typeof valA === 'number' && typeof valB === 'number') {
      return sortOrder === 'desc' ? valB - valA : valA - valB;
    }
    return 0;
  });

  const getRatingIcon = (rating: string) => {
    switch (rating) {
      case '起爆': return <Rocket className="w-4 h-4 text-rose-500" />;
      case '锁筹': return <Lock className="w-4 h-4 text-amber-500" />;
      case '分歧': return <Share2 className="w-4 h-4 text-blue-500" />;
      case '出货': return <Skull className="w-4 h-4 text-slate-500" />;
      default: return <Compass className="w-4 h-4 text-emerald-500" />;
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-rose-600 bg-rose-50 border-rose-100 font-black';
    if (score >= 60) return 'text-amber-600 bg-amber-50 border-amber-100 font-bold';
    return 'text-slate-500 bg-slate-50 border-slate-100 font-medium';
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* Header with Control Panel */}
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 md:p-10 relative overflow-hidden">
        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
            <div>
              <h2 className="text-3xl font-black text-slate-800 flex items-center gap-4 mb-2">
                <div className="p-3 bg-gradient-to-br from-rose-600 to-orange-600 rounded-2xl text-white shadow-xl shadow-rose-100">
                  <ScanEye className="w-8 h-8" />
                </div>
                创业板控盘与趋势动能扫描
              </h2>
              <p className="text-slate-500 text-base max-w-2xl font-medium">
                AI 实时合力搜素今日创业板 **精选 20 只** 核心标的。专注 **控盘深度** 与 **短期进攻动能**，剔除冗余安全垫分析。
              </p>
            </div>

            <button 
              onClick={handleScan}
              disabled={loading}
              className="px-10 h-16 bg-slate-900 text-white rounded-[1.5rem] font-black shadow-2xl hover:bg-slate-800 transition-all flex items-center gap-3 active:scale-95 disabled:opacity-50"
            >
              {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <RefreshCw className="w-6 h-6" />}
              {loading ? `20 只标的高频扫描中 (${elapsed}s)...` : '今日 20 只合力扫盘'}
            </button>
          </div>

          <div className="flex flex-wrap gap-4">
            <div className="flex items-center gap-2 px-4 py-2 bg-indigo-50 border border-indigo-100 rounded-xl text-indigo-700 text-xs font-black">
              <Zap className="w-4 h-4" /> 控盘深度优先
            </div>
            <div className="flex items-center gap-2 px-4 py-2 bg-rose-50 border border-rose-100 rounded-xl text-rose-700 text-xs font-black">
              <Flame className="w-4 h-4" /> 趋势加速探测
            </div>
            <div className="flex items-center gap-2 px-4 py-2 bg-amber-50 border border-amber-100 rounded-xl text-amber-700 text-xs font-black">
              <Target className="w-4 h-4" /> 主力介入成本核对
            </div>
            <div className="flex items-center gap-2 px-4 py-2 bg-slate-100 border border-slate-200 rounded-xl text-slate-500 text-xs font-black">
              <ZapOff className="w-4 h-4" /> 已移除安全垫逻辑
            </div>
          </div>
        </div>
      </div>

      {error && (
        <div className="p-6 bg-rose-50 border border-rose-100 rounded-2xl text-rose-700 flex items-center gap-4 shadow-sm animate-fade-in">
          <ShieldAlert className="w-6 h-6 shrink-0" />
          <span className="font-bold">{error}</span>
        </div>
      )}

      {scanData && (
        <div className="space-y-6 animate-slide-up">
          {/* Market Sentiment Summary */}
          <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white shadow-2xl border-b-8 border-rose-500 relative overflow-hidden">
             <div className="absolute right-0 top-0 w-1/3 h-full bg-gradient-to-l from-rose-500/10 to-transparent pointer-events-none"></div>
             <div className="flex flex-col md:flex-row justify-between items-center gap-6 relative z-10">
                <div className="flex-1">
                   <div className="text-[10px] font-black text-rose-400 uppercase tracking-[0.3em] mb-3">创业板 20 只控盘全景总结 (${scanData.scan_time})</div>
                   <p className="text-xl font-black italic leading-relaxed text-slate-200">"{scanData.market_mood}"</p>
                </div>
                <div className="flex gap-4">
                   {scanData.hot_sectors?.map((sector, idx) => (
                      <span key={idx} className="px-4 py-2 bg-white/10 backdrop-blur-md rounded-xl text-xs font-black border border-white/10">{sector}</span>
                   ))}
                </div>
             </div>
          </div>

          {/* Quant High-Density Table */}
          <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
             <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                   <thead>
                      <tr className="bg-slate-50/80 text-[11px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-200">
                         <th className="px-8 py-5">标的名称 (代码)</th>
                         <th className="px-6 py-5 cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => {setSortKey('control_score'); setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');}}>
                            主力控盘分 {sortKey === 'control_score' && (sortOrder === 'desc' ? '↓' : '↑')}
                         </th>
                         <th className="px-6 py-5">核心成本 / 趋势动能</th>
                         <th className="px-6 py-5">操盘战法</th>
                         <th className="px-6 py-5">明日博弈区间</th>
                         <th className="px-6 py-5 text-right">操盘逻辑</th>
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100">
                      {sortedStocks?.slice(0, 20).map((stock, idx) => (
                         <tr key={idx} className="hover:bg-slate-50/50 transition-all group">
                            <td className="px-8 py-6">
                               <div className="flex items-center gap-4">
                                  <div className="w-8 h-8 rounded-xl bg-slate-100 text-slate-400 flex items-center justify-center font-black text-[10px] group-hover:bg-indigo-600 group-hover:text-white transition-all">
                                     {idx + 1}
                                  </div>
                                  <div>
                                     <div className="font-black text-slate-800 text-lg group-hover:text-indigo-600 transition-colors">{stock.name}</div>
                                     <div className="text-[10px] font-mono text-slate-400">{stock.code}</div>
                                  </div>
                               </div>
                            </td>
                            <td className="px-6 py-6">
                               <div className={`inline-flex items-center justify-center w-14 h-14 rounded-2xl border-2 text-xl shadow-sm ${getScoreColor(stock.control_score)}`}>
                                  {stock.control_score}
                               </div>
                            </td>
                            <td className="px-6 py-6">
                               <div className="text-sm font-black text-slate-700">成本: ¥{stock.cost_price}</div>
                               <div className="flex items-center gap-1.5 mt-1">
                                  <Activity className="w-3 h-3 text-indigo-500" />
                                  <span className="text-xs font-black text-indigo-600">{stock.trend_momentum}</span>
                               </div>
                            </td>
                            <td className="px-6 py-6">
                               <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-xl border-2 text-xs font-black uppercase tracking-widest ${
                                  stock.rating === '起爆' ? 'bg-rose-600 text-white border-rose-700 shadow-md' :
                                  stock.rating === '锁筹' ? 'bg-amber-100 text-amber-700 border-amber-200' :
                                  stock.rating === '出货' ? 'bg-slate-800 text-slate-200 border-slate-900' : 'bg-blue-100 text-blue-700 border-blue-200'
                               }`}>
                                  {getRatingIcon(stock.rating)}
                                  {stock.rating}
                               </div>
                            </td>
                            <td className="px-6 py-6">
                               <div className="flex flex-col gap-1">
                                  <div className="text-[10px] font-black text-rose-500 flex items-center gap-1">↑ 压力: {stock.target_price}</div>
                                  <div className="text-[10px] font-black text-emerald-500 flex items-center gap-1">↓ 支撑: {stock.support_price}</div>
                               </div>
                            </td>
                            <td className="px-6 py-6 text-right">
                               <div className="flex flex-col items-end gap-3">
                                  <p className="text-sm text-slate-500 font-bold max-w-[240px] leading-relaxed line-clamp-2 italic">
                                     "{stock.logic}"
