                      <tr className="bg-slate-50/80 text-[11px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-200">
                         <th className="px-8 py-5">涨停标的 (代码 / 板块)</th>
                         <th className="px-6 py-5 cursor-pointer hover:text-emerald-600 transition-colors" onClick={() => {setSortKey('control_score'); setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');}}>
                            封板强度分 {sortKey === 'control_score' && (sortOrder === 'desc' ? '↓' : '↑')}
